import { cookies } from 'next/headers';
import { redirect } from 'next/navigation';
import bcrypt from 'bcryptjs';
import { prisma } from './db';
import type { Role } from '@prisma/client';
const COOKIE = 'coursehub_session';
export async function hashPassword(password:string){ return bcrypt.hash(password, 10); }
export async function verifyPassword(password:string, hash:string){ return bcrypt.compare(password, hash); }
export async function setSession(userId:string){ (await cookies()).set(COOKIE, userId, { httpOnly:true, sameSite:'lax', secure:false, path:'/', maxAge:60*60*24*7 }); }
export async function clearSession(){ (await cookies()).delete(COOKIE); }
export async function currentUser(){ const id=(await cookies()).get(COOKIE)?.value; if(!id) return null; return prisma.user.findUnique({ where:{id} }); }
export async function requireUser(roles?:Role[]){ const user=await currentUser(); if(!user) redirect('/login'); if(roles && !roles.includes(user.role)) redirect('/dashboard'); return user; }
